INSERT INTO `wp_ig_campaigns` (`id`, `slug`, `name`, `type`, `parent_id`, `parent_type`, `subject`, `body`, `from_name`, `from_email`, `reply_to_name`, `reply_to_email`, `categories`, `list_ids`, `base_template_id`, `status`, `meta`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'sha-publicat-un-article-nou-posttitle', 'S\'ha publicat un article nou:  {{POSTTITLE}}', 'post_notification', NULL, NULL, 'S\'ha publicat un article nou:  {{POSTTITLE}}', 'Hola {{NAME}},\r\n\r\nHem publicat un article nou al nostre lloc web. {{campaign.posts}}{{POSTTITLE}}\r\n{{POSTDESC}}\r\nPodeu veure l\'últim article a {{POSTLINK}}{{/campaign.posts}}\r\nHeu rebut aquest correu perquè vau demanar que se us notifiqués la publicació d\'articles nous\r\n\r\nGràcies i salutacions\r\nAdmin', 'Admin', 'a8000009@xtec.cat', 'Admin', 'a8000009@xtec.cat', '##post:29##', '1', 8841, 1, 'a:1:{s:15:\"list_conditions\";a:1:{i:0;a:1:{i:0;a:3:{s:5:\"field\";s:10:\"_lists__in\";s:8:\"operator\";s:2:\"is\";s:5:\"value\";a:1:{i:0;s:1:\"1\";}}}}}', '2019-05-13 07:43:45', '2024-11-22 10:22:19', '0000-00-00 00:00:00'),
(2, 'envia-un-missatge-de-benvinguda-quan-algu-se-subscriu', 'Envia un missatge de benvinguda quan algú se subscriu', 'workflow', 3, 'workflow', NULL, '', 'Admin', 'a8000009@xtec.cat', 'Admin', 'a8000009@xtec.cat', '', '', 0, 1, NULL, '2024-11-22 10:22:16', '2024-11-22 10:22:17', NULL),
(3, 'maqueta-eoi-benvingut-al-nostre-butlleti', '[Maqueta EOI] Benvingut al nostre butlletí', 'workflow_email', 2, 'workflow', '[Maqueta EOI] Benvingut al nostre butlletí', '<p>Hola {{NAME}}, </p>\n<p> Hem rebut una sol·licitud de subscripci&oacute; d\'aquesta adre&ccedil;a de correu electr&ograve;nic per rebre el bullet&iacute; del nostre lloc web.</p>\n<p>Gr&agrave;cies<br />\nMaqueta EOI</p>\n', 'Admin', 'a8000009@xtec.cat', 'Admin', 'a8000009@xtec.cat', '', '', 0, 1, 'a:3:{s:20:\"enable_open_tracking\";s:2:\"no\";s:20:\"enable_link_tracking\";s:2:\"no\";s:11:\"attachments\";a:0:{}}', '2024-11-22 10:22:16', NULL, NULL),
(6, 'notifica-ladministrador-a-quan-algu-se-subscriu', 'Notifica l\'administrador/a quan algú se subscriu', 'workflow', 5, 'workflow', NULL, '', 'Admin', 'a8000009@xtec.cat', 'Admin', 'a8000009@xtec.cat', '', '', 0, 1, NULL, '2024-11-22 10:22:17', '2024-11-22 10:22:17', NULL),
(7, 'notifica-als-administradors-cada-vegada-que-senvii-un-butlleti', 'Notifica als administradors cada vegada que s\'enviï un butlletí', 'workflow_email', 6, 'workflow', '[Maqueta EOI] Subscripci&oacute; nova de correu', '<p>Hola Administrador, </p>\n<p> Hem rebut una sol·licitud de subscripci&oacute; d\'aquesta adre&ccedil;a de correu electr&ograve;nic per rebre els articles del nostre lloc web. </p>\n<p> Correu electr&ograve;nic : {{EMAIL}}<br />\n Nom : {{NAME}} </p>\n<p>Gr&agrave;cies<br />\nMaqueta EOI</p>\n', 'Admin', 'a8000009@xtec.cat', 'Admin', 'a8000009@xtec.cat', '', '', 0, 1, 'a:3:{s:20:\"enable_open_tracking\";s:2:\"no\";s:20:\"enable_link_tracking\";s:2:\"no\";s:11:\"attachments\";a:0:{}}', '2024-11-22 10:22:17', '2024-11-22 10:22:17', NULL),
(8, 'sha-enviat-el-butlleti', 'S\'ha enviat el butlletí!', 'workflow_email', 7, 'workflow', 'S\'ha enviat el butlletí!', '', 'Admin', 'a8000009@xtec.cat', 'Admin', 'a8000009@xtec.cat', '', '', 0, 1, 'a:3:{s:20:\"enable_open_tracking\";s:2:\"no\";s:20:\"enable_link_tracking\";s:2:\"no\";s:11:\"attachments\";a:0:{}}', '2024-11-22 10:22:17', NULL, NULL);
