(3, 'envia-un-missatge-de-benvinguda-quan-algu-se-subscriu', 'Envia un missatge de benvinguda quan algú se subscriu', 'ig_es_user_subscribed', '', '', 'a:1:{i:0;a:5:{s:11:\"action_name\";s:16:\"ig_es_send_email\";s:13:\"ig-es-send-to\";s:9:\"{{EMAIL}}\";s:19:\"ig-es-email-subject\";s:43:\"[Maqueta EOI] Benvingut al nostre butlletí\";s:19:\"ig-es-email-content\";s:221:\"<p>Hola {{NAME}}, </p>\n<p> Hem rebut una sol·licitud de subscripci&oacute; d\'aquesta adre&ccedil;a de correu electr&ograve;nic per rebre el bullet&iacute; del nostre lloc web.</p>\n<p>Gr&agrave;cies<br />\nMaqueta EOI</p>\n\";s:26:\"ig-es-tracking-campaign-id\";i:3;}}', 1, 1, 0, 'a:1:{s:11:\"when_to_run\";s:11:\"immediately\";}', '2024-11-22 10:22:16', '2024-11-22 10:22:16'),
(4, 'envia-el-missatge-de-confirmacio', 'Envia el missatge de confirmació', 'ig_es_user_unconfirmed', '', '', 'a:1:{i:0;a:5:{s:11:\"action_name\";s:16:\"ig_es_send_email\";s:13:\"ig-es-send-to\";s:9:\"{{EMAIL}}\";s:19:\"ig-es-email-subject\";s:39:\"[Maqueta EOI] confirmeu la subscripció\";s:19:\"ig-es-email-content\";s:339:\"<p>Hola {{NAME}},</p>\n<p> Hem rebut una petici&oacute; de subscripci&oacute; d\'aquesta adre&ccedil;a de correu electr&ograve;nic. Confirmeu <a href=\'{{LINK}}\'>fent clic aqu&iacute;</a>. Si no podeu fer clic a l\'enlla&ccedil; anterior, si us plau, utilitzeu l\'URL seg&uuml;ent.</p>\n<p> {{LINK}} </p>\n<p>Gr&agrave;cies<br />\nMaqueta EOI</p>\n\";s:26:\"ig-es-tracking-campaign-id\";i:5;}}', 1, 1, 0, 'a:1:{s:11:\"when_to_run\";s:11:\"immediately\";}', '2024-11-22 10:22:17', '2024-11-22 10:22:17'),
(5, 'notifica-ladministrador-a-quan-algu-se-subscriu', 'Notifica l\'administrador/a quan algú se subscriu', 'ig_es_user_subscribed', '', '', 'a:1:{i:0;a:5:{s:11:\"action_name\";s:16:\"ig_es_send_email\";s:13:\"ig-es-send-to\";s:17:\"a8000009@xtec.cat\";s:19:\"ig-es-email-subject\";s:47:\"[Maqueta EOI] Subscripci&oacute; nova de correu\";s:19:\"ig-es-email-content\";s:290:\"<p>Hola Administrador, </p>\n<p> Hem rebut una sol·licitud de subscripci&oacute; d\'aquesta adre&ccedil;a de correu electr&ograve;nic per rebre els articles del nostre lloc web. </p>\n<p> Correu electr&ograve;nic : {{EMAIL}}<br />\n Nom : {{NAME}} </p>\n<p>Gr&agrave;cies<br />\nMaqueta EOI</p>\n\";s:26:\"ig-es-tracking-campaign-id\";i:7;}}', 1, 1, 0, 'a:1:{s:11:\"when_to_run\";s:11:\"immediately\";}', '2024-11-22 10:22:17', '2024-11-22 10:22:17'),
(6, 'notifica-als-administradors-cada-vegada-que-senvii-un-butlleti', 'Notifica als administradors cada vegada que s\'enviï un butlletí', 'ig_es_campaign_sent', '', '', 'a:1:{i:0;a:5:{s:11:\"action_name\";s:16:\"ig_es_send_email\";s:13:\"ig-es-send-to\";s:17:\"a8000009@xtec.cat\";s:19:\"ig-es-email-subject\";s:25:\"S\'ha enviat el butlletí!\";s:19:\"ig-es-email-content\";s:0:\"\";s:26:\"ig-es-tracking-campaign-id\";i:8;}}', 1, 1, 0, 'a:1:{s:11:\"when_to_run\";s:11:\"immediately\";}', '2024-11-22 10:22:17', '2024-11-22 10:22:17');
