(8841, 0, '2019-05-13 09:43:45', '2019-05-13 07:43:45', 'Hola {{NAME}},\r\n\r\nHem publicat un article nou al nostre lloc web. {{POSTTITLE}}\r\n{{POSTDESC}}\r\nPodeu veure l\'últim article a {{POSTLINK}}\r\nHeu rebut aquest correu perquè vau demanar que se us notifiqués la publicació d\'articles nous\r\n\r\nGràcies i salutacions\r\nAdmin', 'S\'ha publicat un article nou:  {{POSTTITLE}}', '', 'publish', 'closed', 'closed', '', 'sha-publicat-un-article-nou-posttitle', '', '', '2019-05-13 09:43:45', '2019-05-13 07:43:45', '', 0, 'https://eoi-pre.educaciodigital.cat/mastereoi/es_template/sha-publicat-un-article-nou-posttitle/', 0, 'es_template', '', 0),
(8842, 0, '2019-05-13 09:43:45', '2019-05-13 07:43:45', 'Hola {{EMAIL}},\r\n\r\nHem publicat un article nou al nostre lloc web. {{POSTTITLE}}\r\n{{POSTIMAGE}}\r\n{{POSTFULL}}\r\nPodeu veure l\'últim article a {{POSTLINK}}\r\nHeu rebut aquest correu perquè vau demanar que se us notifiqués la publicació d\'articles nous\r\n\r\nGràcies i salutacions\r\nAdmin', 'Notificació d\'article nou {{POSTTITLE}}', '', 'publish', 'closed', 'closed', '', 'notificacio-darticle-nou-posttitle', '', '', '2019-05-13 09:43:45', '2019-05-13 07:43:45', '', 0, 'https://eoi-pre.educaciodigital.cat/mastereoi/es_template/notificacio-darticle-nou-posttitle/', 0, 'es_template', '', 0),
(8843, 0, '2019-05-13 09:43:45', '2019-05-13 07:43:45', '<strong style=\"color: #990000\"> Subscriptors de correu</strong><p>\r\n							L\'extensió subscripcions de correu de correu té diferents opcions per enviar butlletins als subscriptors.\r\n							Té una pàgina separada amb un editor HTML per crear	un butlletí amb aquest format.\r\n							L\'extensió disposa d\'opcions per enviar correus de notificació als subscriptors quan es publiquen articles nous al lloc web. També té una pàgina per poder afegir i eliminar les categories a les que s\'enviaran les notificacions.\r\n							Utilitzant les opcions de l\'extensió d\'importació i exportació els administradors podran importar fàcilment els usuaris registrats.\r\n						</p> <strong style=\"color: #990000\">Característiques de l\'extensió</strong><ol> <li>Correu de notificació als subscriptors quan es publiquin articles nous.</li> <li>Giny de subscripció</li><li>Correu de subscripció amb confirmació per correu i subscripció simple per facilitar la subscripció.</li> <li>Notificació per correu electrònic a l\'administrador quan els usuaris es subscriguin (Opcional)</li> <li>Correu de benvinguda automàtic als subscriptors (Opcional).</li> <li>Enllaç per donar-se de baixa del correu.</li> <li>Importació / Exportació dels correus dels subscriptors.</li> <li>Editor d\'HTML per redactar el butlletí.</li> </ol> <strong>Gràcies i salutacions</strong><br>Admin', 'Butlletí Hola Món', '', 'publish', 'closed', 'closed', '', 'butlleti-hola-mon', '', '', '2019-05-13 09:43:45', '2019-05-13 07:43:45', '', 0, 'https://eoi-pre.educaciodigital.cat/mastereoi/es_template/butlleti-hola-mon/', 0, 'es_template', '', 0),
(8844, 2, '2019-05-13 12:46:42', '2019-05-13 10:46:42', '{{{ges.action}}}:\n\n<blockquote>{{{usermessage}}}</blockquote>\n&ndash;\n<a href=\"{{{thread.url}}}\">Ves a la discussió</a> per respondre o posar-se al dia de la conversa.\n{{{ges.email-setting-description}}}', '[{{{site.name}}}] {{{ges.subject}}}', '{{{ges.action}}}:\n\n\"{{{usermessage}}}\"\n\nVes a la discussió per respondre o posar-te al dia de la conversa:\n{{{thread.url}}}\n\n----\n\n{{{ges.email-setting-description}}}\n\n{{{ges.email-setting-links}}}', 'publish', 'closed', 'closed', '', 'site-name-ges-subject', '', '', '2019-05-13 12:46:42', '2019-05-13 10:46:42', '', 0, 'https://eoi-pre.educaciodigital.cat/mastereoi/general/site-name-ges-subject/', 0, 'bp-email', '', 0),
