(8900, 2, '2024-11-22 11:22:21', '2024-11-22 10:22:21', 'Aquesta és una notificació del grup {{{group.link}}}:\n\n{{{usermessage}}}\n\n&ndash;\n<strong>Tingueu en compte:</strong> les notificacions d\'administració s\'envien a tothom del node i no es poden deshabilitar.\nSi creieu que el servei s\'està utilitzant malament contacteu amb l\'administrador del lloc web.', '[{{{site.name}}}] {{{ges.subject}}} - del node \"{{{group.name}}}\"', 'Aquesta és una notificació del grup \"{{{group.name}}}\":\n\n\"{{{usermessage}}}\"\n\n----\n\nTingueu en compte: les notificacions d\'administració s\'envien a tothom del node i no es poden deshabilitar.\n\nSi creieu que el servei s\'està utilitzant malament contacteu amb l\'administrador del lloc web.\n\nVisiteu la pàgina d\'inici del node en aquest enllaç:\n{{{group.url}}}', 'publish', 'closed', 'closed', '', 'site-name-ges-subject-del-node-group-name-10', '', '', '2024-11-22 11:22:21', '2024-11-22 10:22:21', '', 0, 'https://eoi-pre.educaciodigital.cat/mastereoi/?p=8900', 0, 'bp-email', '', 0),
